from collections import deque

def can_transform(x, y):
    def next_states(num):
        binary = bin(num)[2:]
        results = []
        for bit in ['0', '1']:
            new_binary = binary + bit
            reversed_binary = new_binary[::-1].lstrip('0')
            if reversed_binary == '':
                reversed_binary = '0'
            results.append(int(reversed_binary, 2))
        return results

    visited = set()
    queue = deque([x])
    visited.add(x)

    while queue:
        current = queue.popleft()
        if current == y:
            return True
        for next_num in next_states(current):
            if next_num == y:
                return True
            if next_num not in visited and next_num <= 2 * 10**18:
                visited.add(next_num)
                queue.append(next_num)

    return False

line = input().split()
x, y = int(line[0]), int(line[1])
if can_transform(x, y):
    print("YES")
